function WeatherCard() { return <div className="mini-panel"><h2>Weather</h2><div className="weather-line"><strong>Live</strong><span>Lewiston/Sabbatus via Open-Meteo</span></div><p className="muted">Later: phone/local route weather + AQI + Sense HAT readings.</p></div>; }
function ActiveTab(props) { if (props.activeTab === 'Explore') return <Explore routes={props.routes} onDownload={props.onDownload} searchQuery={props.searchQuery} selectedRoute={props.selectedRoute} setSelectedRoute={props.setSelectedRoute} onStartRoute={props.onStartRoute} onExportRouteGpx={props.onExportRouteGpx} onDeleteOfflinePack={props.onDeleteOfflinePack} secure={props.secure} conditions={props.conditions} />; if (props.activeTab === 'Plan') return <Plan gpxStatus={props.gpxStatus} onExportGpx={props.onExportGpx} onImportGpx={props.onImportGpx} selectedRoute={props.selectedRoute} customWaypoints={props.customWaypoints} setCustomWaypoints={props.setCustomWaypoints} routeDirty={props.routeDirty} onSaveRoutePack={props.onSaveRoutePack} onDuplicateRoutePack={props.onDuplicateRoutePack} onExportRouteJson={props.onExportRouteJson} onImportRoutePack={props.onImportRoutePack} />; if (props.activeTab === 'Launch') return <Launch selectedRoute={props.selectedRoute} routes={props.routes} setSelectedRoute={props.setSelectedRoute} secure={props.secure} conditions={props.conditions} hiker={props.hiker} originPoint={props.originPoint} onUsePhoneLocation={props.onUsePhoneLocation} launchChecklist={props.launchChecklist} setLaunchChecklist={props.setLaunchChecklist} launchPlan={props.launchPlan} setLaunchPlan={props.setLaunchPlan} readinessLog={props.readinessLog} setReadinessLog={props.setReadinessLog} onStartRoute={props.onStartRoute} onRefreshOfflinePack={props.onRefreshOfflinePack} />; if (props.activeTab === 'Navigate') return <Navigate recording={props.recording} setRecording={props.setRecording} elapsed={props.elapsed} progress={props.progress} setProgress={props.setProgress} resetTrack={props.resetTrack} selectedRoute={props.selectedRoute} launchPlan={props.launchPlan} />; if (props.activeTab === 'Daily Exercise') return <DailyExercise walk={props.walk} setWalk={props.setWalk} conditions={props.conditions} savedWalks={props.savedWalks} setSavedWalks={props.setSavedWalks} onExportWalkGpx={props.onExportWalkGpx} onDeleteWalk={props.onDeleteWalk} />; if (props.activeTab === 'Saved') return <Saved routes={props.routes} savedWalks={props.savedWalks} onExportWalkGpx={props.onExportWalkGpx} onDeleteWalk={props.onDeleteWalk} onExportRouteGpx={props.onExportRouteGpx} onExportRouteJsonFor={props.onExportRouteJsonFor} onDeleteRoutePack={props.onDeleteRoutePack} onDeleteOfflinePack={props.onDeleteOfflinePack} onRefreshOfflinePack={props.onRefreshOfflinePack} onSelectRoute={props.onSelectRoute} />; if (props.activeTab === 'Health') return <Health hiker={props.hiker} setHiker={props.setHiker} conditions={props.conditions} setConditions={props.setConditions} elapsed={props.elapsed} progress={props.progress} healthHistory={props.healthHistory} setHealthHistory={props.setHealthHistory} />; if (props.activeTab === 'Field Kit') return <FieldKit />; if (props.activeTab === 'Survival') return <Survival />; return <Settings settings={props.settings} setSettings={props.setSettings} clearLocalState={props.clearLocalState} />; }

function App() {
  const [activeTab, setActiveTab] = useState(() => loadStored('mappi3.activeTab', 'Explore'));
  const secure = typeof window !== 'undefined' && window.isSecureContext;
  const [originPoint, setOriginPoint] = useState(() => loadStored('mappi3.originPoint', localHome));
  const touchStartX = useRef(null);
  const [searchQuery, setSearchQuery] = useState(() => loadStored('mappi3.searchQuery', ''));
  const [settings, setSettings] = useState(() => loadStored('mappi3.settings', { mode: 'Hotspot', units: 'Miles / °F', theme: 'Topo Night' }));
  const [hiker, setHiker] = useState(() => ({ ...defaultHiker, ...loadStored('mappi3.hiker', {}) }));
  const [conditions, setConditions] = useState(() => ({ ...defaultConditions, ...loadStored('mappi3.conditions', {}) }));
  const [routes, setRoutes] = useState(() => { const stored = loadStored('mappi3.routes', null); if (!stored) return seedRoutes; const storedById = Object.fromEntries(stored.map(route => [route.id, route])); const mergedSeeds = seedRoutes.map(route => ({ ...route, status: storedById[route.id]?.status ?? route.status, tags: storedById[route.id]?.tags ?? route.tags })); const customRoutes = stored.filter(route => route.custom || String(route.id).startsWith('custom-')); return [...mergedSeeds, ...customRoutes]; });
  const [healthHistory, setHealthHistory] = useState(() => loadStored('mappi3.healthHistory', [])); const [customWaypointsByRoute, setCustomWaypointsByRoute] = useState(() => loadStored('mappi3.customWaypointsByRoute', {})); const [selectedRouteId, setSelectedRouteId] = useState(() => loadStored('mappi3.selectedRouteId', seedRoutes[0]?.id)); const selectedBaseRoute = useMemo(() => routes.find(route => route.id === selectedRouteId) || routes[0], [routes, selectedRouteId]); const selectedRoute = useMemo(() => { const route = selectedBaseRoute; return { ...route, customWaypoints: customWaypointsByRoute[route?.id] ?? route?.customWaypoints ?? [] }; }, [selectedBaseRoute, customWaypointsByRoute]); const customWaypoints = selectedRoute.customWaypoints || []; const routeDirty = JSON.stringify(customWaypoints) !== JSON.stringify(selectedBaseRoute?.customWaypoints || []); const setCustomWaypoints = (updater) => setCustomWaypointsByRoute(all => ({ ...all, [selectedRoute.id]: typeof updater === 'function' ? updater(all[selectedRoute.id] || selectedRoute.customWaypoints || []) : updater })); const [recording, setRecording] = useState(false); const [elapsed, setElapsed] = useState(() => loadStored('mappi3.elapsed', 0)); const [progress, setProgress] = useState(() => loadStored('mappi3.progress', 0.34)); const [walk, setWalk] = useState(() => loadStored('mappi3.walk', { active: false, trace: [], ticks: 0, startedAt: null, endedAt: null, source: 'not started' })); const [savedWalks, setSavedWalks] = useState(() => loadStored('mappi3.walkHistory', [])); const [launchChecklist, setLaunchChecklist] = useState(() => loadStored('mappi3.launchChecklist', {})); const [launchPlan, setLaunchPlan] = useState(() => loadStored('mappi3.launchPlan', { waterOz: 0, foodCalories: 0, batteryPercent: 80, powerBankMah: 0, hikeDate: todayKey(), sunTarget: 'sunset', arriveEarlyMin: 15, driveMph: 45, expectedReturn: '', turnAroundTime: '', trailLeaveTime: '', emergencyContact: '', checkInNote: '' })); const [readinessLog, setReadinessLog] = useState(() => loadStored('mappi3.readinessLog', [])); const [gpxStatus, setGpxStatus] = useState('GPX tools ready. Export downloads a sample route file; import stages a mock uploaded GPX.');
  const filteredRoutes = useMemo(() => routes.filter(route => routeMatches(route, searchQuery)), [routes, searchQuery]); const searchSuggestions = useMemo(() => routeSearchSuggestions(routes, searchQuery), [routes, searchQuery]); const downloadedCount = useMemo(() => routes.filter(r => r.status === 'Downloaded').length, [routes]); const healthMetrics = useMemo(() => calcHealth({ hiker, conditions, elapsed, progress }), [hiker, conditions, elapsed, progress]);
  useEffect(() => localStorage.setItem('mappi3.activeTab', JSON.stringify(activeTab)), [activeTab]); useEffect(() => localStorage.setItem('mappi3.originPoint', JSON.stringify(originPoint)), [originPoint]); useEffect(() => localStorage.setItem('mappi3.customWaypointsByRoute', JSON.stringify(customWaypointsByRoute)), [customWaypointsByRoute]); useEffect(() => localStorage.setItem('mappi3.healthHistory', JSON.stringify(healthHistory)), [healthHistory]); useEffect(() => localStorage.setItem('mappi3.selectedRouteId', JSON.stringify(selectedRouteId)), [selectedRouteId]); useEffect(() => localStorage.setItem('mappi3.searchQuery', JSON.stringify(searchQuery)), [searchQuery]); useEffect(() => localStorage.setItem('mappi3.settings', JSON.stringify(settings)), [settings]); useEffect(() => localStorage.setItem('mappi3.routes', JSON.stringify(routes)), [routes]); useEffect(() => localStorage.setItem('mappi3.elapsed', JSON.stringify(elapsed)), [elapsed]); useEffect(() => localStorage.setItem('mappi3.progress', JSON.stringify(progress)), [progress]); useEffect(() => localStorage.setItem('mappi3.hiker', JSON.stringify(hiker)), [hiker]); useEffect(() => localStorage.setItem('mappi3.conditions', JSON.stringify(conditions)), [conditions]); useEffect(() => localStorage.setItem('mappi3.walk', JSON.stringify({ ...walk, active: false })), [walk]); useEffect(() => localStorage.setItem('mappi3.walkHistory', JSON.stringify(savedWalks)), [savedWalks]); useEffect(() => localStorage.setItem('mappi3.launchChecklist', JSON.stringify(launchChecklist)), [launchChecklist]); useEffect(() => localStorage.setItem('mappi3.launchPlan', JSON.stringify(launchPlan)), [launchPlan]); useEffect(() => localStorage.setItem('mappi3.readinessLog', JSON.stringify(readinessLog)), [readinessLog]);
  useEffect(() => { if (!recording) return undefined; const timer = setInterval(() => { setElapsed(e => e + 1); setProgress(p => (p >= 0.98 ? 0.02 : Math.min(0.99, p + 0.012))); }, 1000); return () => clearInterval(timer); }, [recording]);
  useEffect(() => {
    let cancelled = false;
    async function loadWeather() {
      try {
        const weatherPoint = originPoint || localHome;
        const forecastUrl = `https://api.open-meteo.com/v1/forecast?latitude=${weatherPoint.lat}&longitude=${weatherPoint.lon}&current=temperature_2m,relative_humidity_2m&temperature_unit=fahrenheit&timezone=auto`;
        const airUrl = `https://air-quality-api.open-meteo.com/v1/air-quality?latitude=${weatherPoint.lat}&longitude=${weatherPoint.lon}&current=us_aqi`;
        const [forecast, air] = await Promise.all([fetch(forecastUrl).then(r => r.json()), fetch(airUrl).then(r => r.json()).catch(() => null)]);
        if (cancelled) return;
        setConditions(c => ({
          ...c,
          source: 'Open-Meteo live',
          location: weatherPoint.label || localHome.label,
          tempF: Math.round(forecast?.current?.temperature_2m ?? c.tempF),
          humidity: Math.round(forecast?.current?.relative_humidity_2m ?? c.humidity),
          airQuality: Math.round(air?.current?.us_aqi ?? c.airQuality),
          elevationFt: c.elevationFt || 203
        }));
      } catch {
        if (!cancelled) setConditions(c => ({ ...c, source: 'Local fallback' }));
      }
    }
    loadWeather();
    return () => { cancelled = true; };
  }, [originPoint?.lat, originPoint?.lon]);
  const saveRoutePack = (name = selectedRoute.name) => { const now = Date.now(); const id = selectedRoute.custom ? selectedRoute.id : `custom-${now}`; const saved = { ...selectedRoute, id, name: name || selectedRoute.name, custom: true, sourceRouteId: selectedRoute.sourceRouteId || selectedRoute.id, status: 'Downloaded', tags: Array.from(new Set([...(selectedRoute.tags || []), 'custom', 'saved'])), customWaypoints, savedAt: now, updatedAt: now }; setRoutes(rs => selectedRoute.custom ? rs.map(route => route.id === id ? saved : route) : [saved, ...rs]); setCustomWaypointsByRoute(all => ({ ...all, [id]: customWaypoints })); setSelectedRouteId(id); setGpxStatus(`Saved local route pack: ${saved.name}.`); };
  const duplicateRoutePack = (name = `Copy of ${selectedRoute.name}`) => { const now = Date.now(); const copy = { ...selectedRoute, id: `custom-${now}`, name, custom: true, sourceRouteId: selectedRoute.sourceRouteId || selectedRoute.id, status: 'Downloaded', tags: Array.from(new Set([...(selectedRoute.tags || []), 'custom', 'duplicate'])), customWaypoints, savedAt: now, updatedAt: now }; setRoutes(rs => [copy, ...rs]); setCustomWaypointsByRoute(all => ({ ...all, [copy.id]: customWaypoints })); setSelectedRouteId(copy.id); setActiveTab('Plan'); setGpxStatus(`Duplicated route pack: ${copy.name}.`); };
  const exportRouteJson = () => downloadTextFile(`${(selectedRoute.name || 'mappi3-route-pack').toLowerCase().replace(/[^a-z0-9]+/g, '-')}.mappi3.json`, makeRoutePackJson(selectedRoute), 'application/json');
  const exportRouteJsonFor = (route) => downloadTextFile(`${(route.name || 'mappi3-route-pack').toLowerCase().replace(/[^a-z0-9]+/g, '-')}.mappi3.json`, makeRoutePackJson(route), 'application/json');
  const importRoutePack = (incoming) => { const result = validateRoutePackPayload({ route: incoming }); if (!result.ok) { setGpxStatus(`Import failed: ${result.error}`); return; } const imported = result.route; const id = imported.id || `custom-${Date.now()}`; const route = { ...imported, id, custom: true, status: imported.status || 'Downloaded', tags: Array.from(new Set([...(imported.tags || []), 'custom', 'imported'])) }; setRoutes(rs => [route, ...rs.filter(item => item.id !== id)]); setCustomWaypointsByRoute(all => ({ ...all, [id]: route.customWaypoints || [] })); setSelectedRouteId(id); setActiveTab('Plan'); setGpxStatus(`Imported JSON route pack: ${route.name || id}.`); };
  const deleteRoutePack = (id) => { setRoutes(rs => rs.filter(route => route.id !== id || !route.custom)); setCustomWaypointsByRoute(all => { const next = { ...all }; delete next[id]; return next; }); if (selectedRouteId === id) setSelectedRouteId(seedRoutes[0]?.id); setGpxStatus('Deleted local custom route pack.'); };
  const onDownload = (id) => setRoutes(rs => rs.map(route => route.id === id ? { ...route, status: 'Downloaded', offlineSavedAt: Date.now(), offlineStaleAfterDays: 14, tags: Array.from(new Set([...(route.tags || []), 'downloaded'])) } : route)); const deleteOfflinePack = (id) => setRoutes(rs => rs.map(route => route.id === id ? { ...route, status: route.custom ? 'Downloaded' : 'Ready', offlineSavedAt: null, tags: (route.tags || []).filter(t => t !== 'downloaded') } : route)); const refreshOfflinePack = (id) => onDownload(id); const onStartRoute = (route) => { setSelectedRouteId(route.id); setProgress(0); setElapsed(0); setRecording(true); setActiveTab('Navigate'); }; const resetTrack = () => { setRecording(false); setElapsed(0); setProgress(0); };
  const onExportGpx = () => { downloadTextFile('mappi3-sample-route.gpx', makeGpx(), 'application/gpx+xml'); setGpxStatus(`Exported mappi3-sample-route.gpx from ${primaryRoutePack.name}.`); }; const onExportRouteGpx = (route) => downloadTextFile(`${(route.name || 'mappi3-route').toLowerCase().replace(/[^a-z0-9]+/g, '-')}.gpx`, makeRouteGpx(route), 'application/gpx+xml'); const onExportWalkGpx = (item) => downloadTextFile(`${(item.name || 'mappi3-walk').toLowerCase().replace(/[^a-z0-9]+/g, '-')}.gpx`, makeWalkGpx(item), 'application/gpx+xml'); const onDeleteWalk = (id) => setSavedWalks(items => items.filter(item => (item.id || item.savedAt) !== id)); const onImportGpx = () => setGpxStatus('Mock import staged: sample GPX would be parsed into route geometry, waypoints, POIs, and an offline pack request.'); const clearLocalState = () => { ['mappi3.activeTab','mappi3.originPoint','mappi3.selectedRouteId','mappi3.searchQuery','mappi3.settings','mappi3.routes','mappi3.elapsed','mappi3.progress','mappi3.hiker','mappi3.healthHistory','mappi3.customWaypointsByRoute','mappi3.conditions','mappi3.walk','mappi3.walkHistory','mappi3.launchChecklist','mappi3.launchPlan','mappi3.readinessLog'].forEach(k => localStorage.removeItem(k)); location.reload(); }; const goTab = (delta) => { const index = tabs.indexOf(activeTab); setActiveTab(tabs[(index + delta + tabs.length) % tabs.length]); }; const onTouchStart = (event) => { if (event.target.closest('input, textarea, select, button, .leaflet-container')) return; touchStartX.current = event.touches[0].clientX; }; const onTouchEnd = (event) => { if (touchStartX.current === null) return; const dx = event.changedTouches[0].clientX - touchStartX.current; touchStartX.current = null; if (Math.abs(dx) > 70) goTab(dx < 0 ? 1 : -1); }; const onUsePhoneLocation = () => { if (!navigator.geolocation || !secure) { setGpxStatus('Phone location needs the Tailscale HTTPS URL and browser location permission.'); return; } navigator.geolocation.getCurrentPosition(pos => { setOriginPoint({ label: `phone GPS ±${Math.round(pos.coords.accuracy || 0)}m`, lat: pos.coords.latitude, lon: pos.coords.longitude }); setGpxStatus('Phone GPS origin saved for trailhead travel estimate.'); }, err => setGpxStatus(`Phone GPS origin unavailable: ${err.message}`), { enableHighAccuracy: true, maximumAge: 60000, timeout: 12000 }); };
  return <main className="app-shell" onTouchStart={onTouchStart} onTouchEnd={onTouchEnd}><section className="hero-card"><div className="top-line"><span className="brand-mark">△</span><div><h1>MapPi3</h1><p>Trail OS · {VERSION}</p></div><Pill tone="online">{settings.mode}</Pill></div><div className="search-box"><span>⌕</span><input placeholder="Search places, trails, foods, water, saved GPX…" value={searchQuery} onChange={e => { setSearchQuery(e.target.value); setActiveTab('Explore'); }} /><button className="ghost small" onClick={() => setSearchQuery('')}>Clear</button></div><div className="route-quick-filters">{routeQuickFilters.map(filter => <button key={filter} onClick={() => { setSearchQuery(filter); setActiveTab('Explore'); }}>{filter}</button>)}<button onClick={onUsePhoneLocation}>use current GPS</button></div>{searchQuery && <div className="route-suggest">{searchSuggestions.map(item => <button key={item} onClick={() => { setSearchQuery(item); setActiveTab('Explore'); }}>{item}</button>)}</div>}<div className="search-hint">{searchQuery ? `${filteredRoutes.length} route match(es). Route search is active. Food/drink custom entry lives in Health.` : 'Swipe left/right anywhere outside controls to change pages.'}</div><div className="quick-stats"><Stat value={(progress * primaryRoutePack.distanceMiles).toFixed(1)} label="hike mi" /><Stat value={formatClock(elapsed)} label="elapsed" /><Stat value={Math.round(healthMetrics.caloriesBurned)} label="cal burned" /><Stat value={`${downloadedCount}/${routes.length}`} label="packs local" /></div></section><section className="tabs-grid" aria-label="MapPi3 sections">{tabs.map(item => <button key={item} className={item === activeTab ? 'active' : ''} onClick={() => setActiveTab(item)}>{item}</button>)}</section><ActiveTab activeTab={activeTab} routes={filteredRoutes} searchQuery={searchQuery} selectedRoute={selectedRoute} customWaypoints={customWaypoints} setCustomWaypoints={setCustomWaypoints} routeDirty={routeDirty} onSaveRoutePack={saveRoutePack} onDuplicateRoutePack={duplicateRoutePack} onExportRouteJson={exportRouteJson} onImportRoutePack={importRoutePack} onExportRouteJsonFor={exportRouteJsonFor} onDeleteRoutePack={deleteRoutePack} onDeleteOfflinePack={deleteOfflinePack} onRefreshOfflinePack={refreshOfflinePack} secure={secure} conditions={conditions} hiker={hiker} originPoint={originPoint} onUsePhoneLocation={onUsePhoneLocation} launchChecklist={launchChecklist} setLaunchChecklist={setLaunchChecklist} launchPlan={launchPlan} setLaunchPlan={setLaunchPlan} readinessLog={readinessLog} setReadinessLog={setReadinessLog} onSelectRoute={(id) => { setSelectedRouteId(id); setActiveTab('Plan'); }} setSelectedRoute={(route) => setSelectedRouteId(route?.id)} onStartRoute={onStartRoute} onExportRouteGpx={onExportRouteGpx} onDownload={onDownload} settings={settings} setSettings={setSettings} recording={recording} setRecording={setRecording} elapsed={elapsed} progress={progress} setProgress={setProgress} resetTrack={resetTrack} gpxStatus={gpxStatus} onExportGpx={onExportGpx} onImportGpx={onImportGpx} clearLocalState={clearLocalState} hiker={hiker} setHiker={setHiker} healthHistory={healthHistory} setHealthHistory={setHealthHistory} conditions={conditions} setConditions={setConditions} walk={walk} setWalk={setWalk} savedWalks={savedWalks} setSavedWalks={setSavedWalks} onExportWalkGpx={onExportWalkGpx} onDeleteWalk={onDeleteWalk} /></main>;
}
createRoot(document.getElementById('root')).render(<App />);
